-- Table schema (idempotent)
CREATE TABLE IF NOT EXISTS marketplace_skills (
    skill_id VARCHAR(20) PRIMARY KEY,
    registry_id VARCHAR(8) NOT NULL,
    name VARCHAR(100) NOT NULL,
    display_name VARCHAR(200) NOT NULL,
    version VARCHAR(10) DEFAULT '1.0.0',
    category VARCHAR(50),
    thread VARCHAR(50),
    thread_code VARCHAR(5),
    domain VARCHAR(20),
    description TEXT,
    trigger_keywords TEXT,
    delegation_targets VARCHAR(100),
    key_systems VARCHAR(100),
    sovereignty_score INTEGER DEFAULT 7,
    governance_level VARCHAR(20) DEFAULT 'advisory',
    psi_minimum DECIMAL(5,2) DEFAULT 10.00,
    status VARCHAR(20) DEFAULT 'published',
    author VARCHAR(200),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

