INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2056', '2123eb9e', 'sandbox-sdk', 'Sandbox Sdk', '1.0.0', 'cloud-aws', 'T13 — ACAI V2', 'T13', 'infrastructure', 'Build sandboxed applications for secure code execution. Load when building AI code execution, code interpreters, CI/CD systems, interactive dev environments, or executing untrusted code. Covers Sandbox SDK lifecycle, commands, files, code interpreter, and preview URLs. Biases towards retrieval from Cloudflare docs over pre-trained knowledge.', '', '', 'Marel', 8, 'restricted', 10.0, 'draft', 'cloudflare/skills');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2057', '3fc3cd60', 'web-perf', 'Web Perf', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Analyzes web performance using Chrome DevTools MCP. Measures Core Web Vitals (FCP, LCP, TBT, CLS, Speed Index), identifies render-blocking resources, network dependency chains, layout shifts, caching issues, and accessibility gaps. Use when asked to audit, profile, debug, or optimize page load performance, Lighthouse scores, or site speed. Biases towards retrieval from current documentation over pre-trained knowledge.', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cloudflare/skills');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2058', 'fa771ab7', 'workers-best-practices', 'Workers Best Practices', '1.0.0', 'cloud-aws', 'T13 — ACAI V2', 'T13', 'infrastructure', 'Reviews and authors Cloudflare Workers code against production best practices. Load when writing new Workers, reviewing Worker code, configuring wrangler.jsonc, or checking for common Workers anti-patterns (streaming, floating promises, global state, secrets, bindings, observability). Biases towards retrieval from Cloudflare docs over pre-trained knowledge.', '', '', 'Marel', 8, 'restricted', 10.0, 'draft', 'cloudflare/skills');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2059', 'db26059c', 'wrangler', 'Wrangler', '1.0.0', 'cloud-aws', 'T13 — ACAI V2', 'T13', 'infrastructure', 'Cloudflare Workers CLI for deploying, developing, and managing Workers, KV, R2, D1, Vectorize, Hyperdrive, Workers AI, Containers, Queues, Workflows, Pipelines, and Secrets Store. Load before running wrangler commands to ensure correct syntax and best practices. Biases towards retrieval from Cloudflare docs over pre-trained knowledge.', '', '', 'Marel', 8, 'restricted', 10.0, 'draft', 'cloudflare/skills');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2060', '1b39b899', 'accessibility-system', 'Accessibility System', '1.0.0', 'testing', 'T04 — ACIW', 'T04', 'cognitive', 'You are an accessibility specialist building inclusive digital experiences, not just checking WCAG compliance boxes. This skill covers the complete accessibility design system: focus management, screen reader navigation patterns, ARIA semantics, keyboard-only navigation, form error handling, color-independent design, and automated testing integration. Target WCAG 2.2 AA (minimum) with AAA considerations. Emphasize that accessibility is a design principle, not a feature bolted on at the end.', '', '', 'AcuTect-CODEX', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2061', 'f91d52db', 'ad-creative-design', 'Ad Creative Design', '1.0.0', 'cloud-aws', 'T13 — ACAI V2', 'T13', 'infrastructure', 'Paid ad platforms have ruthless auto-cropping, strict text limits, and algorithmic penalization for poor design. A creative that performs well on Facebook bombs on TikTok Ads. A Google Responsive Display Ad at the wrong size tanks impression share. This skill provides exact specs, visual hierarchy rules, CTA patterns, and platform-specific copy integration so your ads pass quality review AND hit performance targets.', '', '', 'Marel', 8, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2062', '5ddc7e85', 'aesthetic-direction', 'Aesthetic Direction', '1.0.0', 'mind-clone', 'T03 — HISN', 'T03', 'cognitive', 'You are a visual strategist. This skill guides projects toward intentional, cohesive aesthetic directions by asking about context, then presenting curated options with full design briefs. Instead of letting aesthetics emerge accidentally, you shape them deliberately using proven frameworks: industry patterns, audience expectations, brand personality, and technical constraints.', '', '', 'Baranurion-L1', 10, 'sovereign', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2063', '1934b495', 'agentic-ui', 'Agentic Ui', '1.0.0', 'agent-patterns', 'T01 — COSM', 'T01', 'cognitive', 'You are designing AI-native interfaces for a 2026+ world where every app is AI-powered. This skill provides production-ready patterns for intent preview (showing users what AI will do before execution), autonomy controls (letting users choose between manual/supervised/autonomous AI actions), task decomposition UI (breaking goals into steps), streaming states, tool call transparency, confidence indicators, and error recovery. Most AI features in production apps aren''t chat — they''re inline sugges', '', '', 'Diaran-MOE', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2064', '6be6df79', 'app-design-system', 'App Design System', '1.0.0', 'blockchain', 'T01 — COSM', 'T01', 'infrastructure', 'Design system wizard for applications (SaaS, mobile apps, web apps, PWAs) covering navigation architecture, state management UI, form systems, notification hierarchies, and platform-specific adaptations. Distinct from marketing site design systems. Use for app redesigns, component library definition, and multi-platform consistency.', '', '', 'ADOCP', 9, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2065', '83275deb', 'background-removal', 'Background Removal', '1.0.0', 'multimodal', 'T03 — HISN', 'T03', 'cognitive', 'This skill provides production integration with the remove.bg API to automatically remove backgrounds from images. Use it to process product photos, headshots, social media assets, and creative materials into transparent PNGs. The API uses AI to detect subjects (person, product, car, animal) and cleanly removes backgrounds.', '', '', 'Baranurion-L1', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2066', '409723eb', 'bento-layout', 'Bento Layout', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Bento layouts create visually dynamic, asymmetric grid layouts using CSS Grid. Unlike uniform grids, bento boxes vary in size (1 column × 1 row, 2 columns × 1 row, 1 column × 2 rows, etc.) to highlight key content and create visual hierarchy. This skill provides production-ready Tailwind CSS Grid patterns for React, Astro, and HTML.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2067', 'a6b32f03', 'brand-identity-system', 'Brand Identity System', '1.0.0', 'auth', 'T09 — Q-Suite', 'T09', 'security', 'A brand identity system is the complete visual, verbal, and experiential expression of an organization across all touchpoints. This skill orchestrates the full lifecycle of brand creation: discovery, strategy definition, visual identity design, and implementation guidelines across web, social, advertising, and print.', '', '', 'Q-ENC', 10, 'sovereign', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2068', 'a94bcad8', 'brand-research', 'Brand Research', '1.0.0', 'search', 'T02 — DIAR', 'T02', 'cognitive', 'You are a brand intelligence specialist. This skill fetches structured brand data from any domain using the Brandfetch API, extracting logos, color palettes, fonts, company information, and visual guidelines. Use this to rapidly gather design assets and reference material for competitor analysis, client onboarding, or design inspiration during concept phases.', '', '', 'APMS', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2069', '5523bfb5', 'client-deliverables', 'Client Deliverables', '1.0.0', 'agent-patterns', 'T01 — COSM', 'T01', 'cognitive', 'You are the output layer for design systems and client work. This workflow orchestrates all other design-agent skills to produce professional, branded deliverables that tell a story: Problem → Analysis → Recommendation → Next Steps. Instead of dumping raw design data, you package design work into three key formats: **structured markdown** (for hosting as web pages), **PDF exports** (for email/archival), and **XLSX reports** (for metrics-driven clients). Each deliverable follows Anderson Collabor', '', '', 'Diaran-MOE', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2070', '1c590fe0', 'color-system', 'Color System', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'You are a color systems architect. This skill generates production-ready color systems starting from a single base color, applying color theory principles to create cohesive, accessible palettes. You''ll produce CSS custom properties, Tailwind config extensions, dark mode variants, WCAG contrast checks, and gradient recipes (mesh gradients, grain overlays, glassmorphism).', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2071', '78db53cd', 'competitive-design-intel', 'Competitive Design Intel', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Automated competitive design analysis workflow. Orchestrates brand research, visual audit scoring, and design critique to produce intelligence reports comparing 2-5 competitors. Use for client proposals, redesign justification, market positioning analysis, and differentiation strategy.', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2072', 'b6af4bd3', 'component-patterns', 'Component Patterns', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'This skill provides production-ready best practices for building accessible, consistent, well-designed UI components. It synthesizes guidance from 95+ design systems (Shopify Polaris, IBM Carbon, Atlassian, Material Design, Radix, shadcn/ui) and covers the 20 most-used components across 7 categories. Each component includes anatomy, states, accessibility requirements, and anti-patterns to avoid.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2073', '9be73b1c', 'dark-mode', 'Dark Mode', '1.0.0', 'rag', 'T02 — DIAR', 'T02', 'cognitive', 'You are a dark mode implementation specialist. This skill covers CSS custom properties for theme tokens, Tailwind''s `dark:` variant, system preference detection via `prefers-color-scheme`, manual toggle with localStorage, color mapping strategies, image adaptation, and WCAG contrast requirements for dark backgrounds.', '', '', 'APMS', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2074', '6938aa60', 'dashboard-patterns', 'Dashboard Patterns', '1.0.0', 'cloud-aws', 'T13 — ACAI V2', 'T13', 'infrastructure', 'This skill provides production-ready layouts and component patterns for dashboards, admin panels, analytics interfaces, and data-heavy applications. Dashboards require special handling: progressive data loading (skeleton states), empty states (no data yet), error states (API failed), and chart selection (pick the right visualization). The skill covers information architecture (hierarchy), chart selection guide (which visualization for which data), component patterns (KPI cards, data tables, filt', '', '', 'Marel', 8, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2075', 'cf5e39da', 'data-visualization', 'Data Visualization', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Data visualization turns numbers into understanding. Choosing the wrong chart type, poor color usage, or inaccessible design makes data meaningless. This skill covers chart selection, visual encoding, and implementation patterns for web applications.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2076', '4b980c35', 'design-critique', 'Design Critique', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'You are a design critic and quality assessor. This skill provides a structured, repeatable framework for evaluating web designs across eight dimensions. Each dimension gets a 1-10 score with specific, measurable criteria, producing a composite Design Quality Score (DQS). Output: scored audit with prioritized, actionable fixes — not vague "make it better" feedback.', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2077', 'b8c91590', 'design-handoff', 'Design Handoff', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'The gap between design and development is where most quality is lost. This skill codifies the handoff process into a structured workflow that gives developers everything they need to implement pixel-perfect, interactive, responsive interfaces without guesswork, approvals cycles, or back-and-forth questions.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2078', '9d9cc46c', 'design-qa', 'Design Qa', '1.0.0', 'testing', 'T04 — ACIW', 'T04', 'cognitive', 'Systematic design quality assurance before launch. Visual regression testing catches unintended changes, cross-browser checks catch rendering issues, and pre-launch checklists catch everything else. This skill formalizes the QA workflows that separate "looks good on my machine" from "ready for production."', '', '', 'AcuTect-CODEX', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2079', 'ef71036f', 'design-system-generator', 'Design System Generator', '1.0.0', 'agent-patterns', 'T01 — COSM', 'T01', 'cognitive', 'You are a design systems architect. This skill orchestrates the complete process of building a cohesive, scalable design system from brand strategy to production tokens. Instead of designing ad-hoc, you''ll establish systematic, documented design decisions that front-end developers can implement immediately and designers can extend predictably.', '', '', 'Diaran-MOE', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2080', 'd269b5aa', 'design-to-code', 'Design To Code', '1.0.0', 'agent-patterns', 'T01 — COSM', 'T01', 'cognitive', 'Design-to-Code is a 6-phase orchestration workflow that transforms a brief into production-ready frontend code. Unlike isolated design or code tasks, this skill integrates the full pipeline: gathering requirements, establishing visual direction, researching context, building a design system, structuring layouts, and generating code.', '', '', 'Diaran-MOE', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2081', '6b37278b', 'design-tokens', 'Design Tokens', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'for each token: if $value contains {alias}: resolve(alias)  # Error if circular ```', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2082', 'd367d4e7', 'email-design', 'Email Design', '1.0.0', 'multimodal', 'T03 — HISN', 'T03', 'cognitive', 'This skill provides production-ready email templates and HTML best practices for rendering reliably across the 4 major email clients (Gmail, Outlook, Apple Mail, Yahoo). Email is fundamentally different from web design: Outlook uses Word''s HTML renderer (not a browser), most clients strip CSS stylesheets, dark mode requires special handling, and images may be blocked. This skill teaches the constraints, patterns, and templates to ship emails that look consistent across 95%+ of inboxes.', '', '', 'Baranurion-L1', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2083', 'f6b5a8c4', 'error-states', 'Error States', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Every app breaks. The question is whether it breaks gracefully. Error states are a design opportunity — they maintain trust, guide recovery, and can even delight. This skill covers every error and empty state pattern a production app needs.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2084', 'fe891a08', 'figma-pipeline', 'Figma Pipeline', '1.0.0', 'figma', 'T14 — NAHRA', 'T14', 'commercial', 'https://figma.com/file/{fileKey}/MyProject?node-id={nodeId}', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2085', 'c6baffc5', 'form-design', 'Form Design', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Forms are where conversions happen—signups, checkouts, contact requests. Bad forms kill conversion rates. This skill covers input patterns, validation strategies, multi-step flows, and accessibility for forms that people actually complete.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2086', '78427956', 'gsap-animations', 'Gsap Animations', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'GSAP (GreenSock Animation Platform) is the industry standard for production web animations. Used on 11M+ sites including Apple, Google, Nike, and award-winning agencies. This skill covers timeline sequencing, scroll-linked effects, typography animations, and performance patterns for modern web applications.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2087', 'f655bb0f', 'i18n-rtl', 'I18N Rtl', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'You are building interfaces that work seamlessly across languages and writing systems (left-to-right and right-to-left). This skill covers the complete i18n and RTL design system: CSS logical properties, bidirectional text handling, locale-aware typography and spacing, number/date formatting via native APIs, and component mirroring strategies. The goal is a single codebase that adapts fluidly to any language — no separate RTL builds, no hardcoded directions.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2088', '6b43cc44', 'icon-systems', 'Icon Systems', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Icon systems provide a foundational design language for interfaces. This skill covers the selection, implementation, and optimization of icon libraries across web and app projects. It establishes sizing tokens, accessibility patterns, and performance best practices that scale from small UI icons to large illustration systems.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2089', '05a2cfbe', 'image-optimization', 'Image Optimization', '1.0.0', 'multimodal', 'T03 — HISN', 'T03', 'cognitive', 'Image optimization is the single biggest performance lever for most websites. This skill covers format selection, responsive delivery, loading strategies, and integration with modern frameworks. Properly optimized images reduce file size by 50-80%, improve Core Web Vitals (LCP, CLS), and directly impact conversion rates and SEO rankings.', '', '', 'Baranurion-L1', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2090', '7728ef4a', 'landing-page-patterns', 'Landing Page Patterns', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Landing-Page-Patterns provides battle-tested high-conversion templates for every major section of a sales/promotional site. This skill combines **CRO psychology** (conversion rate optimization) with production-ready Tailwind code, so you can build landing pages that not only look professional but also convert visitors into customers, signups, or leads.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2091', '7d943000', 'lottie-rive', 'Lottie Rive', '1.0.0', 'rag', 'T02 — DIAR', 'T02', 'cognitive', 'Lottie and Rive render designer-created vector animations in the browser at any resolution without quality loss. Lottie plays After Effects exports. Rive adds interactivity with state machines. Together they replace GIFs, video, and CSS for complex animations like loading states, onboarding illustrations, and micro-interactions.', '', '', 'APMS', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2092', 'eb23d0ee', 'micro-interactions', 'Micro Interactions', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Micro-interactions are the small animations and transitions that make interfaces feel alive and responsive. Every click, hover, and state change is an opportunity to provide visual feedback and confirm user actions. The difference between a flat, unresponsive interface and a polished product often comes down to these subtle moments of motion.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2093', '32fd82e9', 'motion-design', 'Motion Design', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'You are a motion design specialist for web. This skill covers animation patterns that enhance UX without degrading performance. Focus on CSS transitions, Framer Motion (React), scroll-triggered animations via Intersection Observer, micro-interactions, loading skeletons, page transitions, and animation choreography with strict adherence to GPU performance rules and accessibility requirements.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2094', '6b12da93', 'navigation-patterns', 'Navigation Patterns', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Navigation is the backbone of usability. Bad navigation loses users. This skill covers every major navigation pattern with clear decision criteria for when to use each, accessibility requirements, and responsive behavior from 375px to 4K displays.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2095', 'd5e41f71', 'onboarding-ux', 'Onboarding Ux', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'First impressions determine whether users stay or churn. Onboarding patterns guide new users from signup to their "aha moment" — the first time they experience real value.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2096', 'd9a87a6e', 'page-transitions', 'Page Transitions', '1.0.0', 'coding', 'T04 — ACIW', 'T04', 'cognitive', 'You are a page transition specialist. This skill covers the browser-native View Transitions API for animating between page states without JavaScript animation libraries. Handles cross-fade, slide, and shared element morphing transitions. Works with both SPA (single-page apps) and MPA (multi-page apps) architectures, with framework-specific integrations for Next.js, Astro, and vanilla HTML.', '', '', 'AcuTect-CODEX', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2097', '5f4effb0', 'print-design', 'Print Design', '1.0.0', 'cloud-aws', 'T13 — ACAI V2', 'T13', 'infrastructure', 'Print-ready design specs for business collateral (business cards, letterhead, envelopes, flyers, brochures, postcards, posters, banners, table tents). Covers exact dimensions with bleed, DPI, CMYK color mode, font embedding, file formats, paper stock guidance, and technical requirements for print vendors.', '', '', 'Marel', 8, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2098', '9543d8fb', 'responsive-patterns', 'Responsive Patterns', '1.0.0', 'multimodal', 'T03 — HISN', 'T03', 'cognitive', 'You are a responsive design specialist. This skill provides production-ready patterns for building layouts that work seamlessly from 320px mobile to 2560px ultrawide. Focus on Tailwind CSS mobile-first approach, fluid typography, container queries, responsive images, and touch-friendly interactions. Every layout you build must pass mobile-first design reviews with zero usability friction on small screens.', '', '', 'Baranurion-L1', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2099', '952a4caf', 'scroll-animations', 'Scroll Animations', '1.0.0', 'coding', 'T04 — ACIW', 'T04', 'cognitive', 'You are a scroll animation specialist building next-generation animations using the native Scroll-driven Animations spec. This skill covers pure CSS animations linked to scroll position or element visibility—no JavaScript scroll event handlers needed. Focus on `animation-timeline: scroll()` for container-linked animations (progress bars, parallax) and `animation-timeline: view()` for viewport-linked animations (entrance effects, intersection-triggered reveals). All patterns run on the compositor', '', '', 'AcuTect-CODEX', 10, 'mandatory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2100', 'ad612730', 'seo-design-patterns', 'Seo Design Patterns', '1.0.0', 'search', 'T02 — DIAR', 'T02', 'cognitive', 'Design decisions directly impact search rankings. This skill bridges the gap between visual design and SEO by covering the patterns search engines understand and reward: semantic HTML that structures information correctly, structured data that wins rich snippets, heading hierarchies that shape discoverability, and Core Web Vitals design choices that affect ranking signals. You are not an SEO strategist—you are a designer who understands how your HTML decisions and interaction patterns affect dis', '', '', 'APMS', 9, 'restricted', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2101', '63e55369', 'social-media-design', 'Social Media Design', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Social media platforms each demand unique dimensions, aspect ratios, and text constraints. Creating content at the wrong size tanks engagement—cropped logos, unreadable text, awkward spacing. This skill provides exact platform specifications, safe zones, file requirements, and production-ready Tailwind CSS preview templates so you never ship suboptimal social creatives again.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2102', '9f52f0d8', 'spacing-layout-system', 'Spacing Layout System', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Spacing is the most underrated design skill. Consistent spacing creates visual hierarchy, rhythm, and professionalism. Combined with modern CSS Grid and Flexbox, spacing systems are the foundation every layout is built on. This skill covers spacing tokens, advanced grid patterns, and layout composition.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2103', '9df53b88', 'typography-animation', 'Typography Animation', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'Typography animation is the highest-impact motion on any page — it''s what users read first. From subtle character reveals to dramatic kinetic type, these patterns create memorable first impressions. This skill covers every text animation technique from CSS-only to GSAP SplitText.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2104', '02cc9ef3', 'typography-pairing', 'Typography Pairing', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'You are a typography strategist. This skill provides six opinionated, production-ready font pairings using free commercial fonts from Fontshare. Each pairing includes a display font + body font, type scale recommendations, CSS imports, and usage guidance. Use this to rapidly establish cohesive typography systems without the friction of font selection paralysis.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2105', '3271e590', 'visual-audit', 'Visual Audit', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'A visual audit systematically evaluates design quality across seven critical dimensions: typography, color, spacing, layout, components, motion, and accessibility. The audit uses a scoring framework (Design Feasibility & Impact Index — DFII from Anthropic''s frontend-design skill) to quantify improvements and prioritize fixes. Output: scored report with specific issues, impact levels, and quick wins.', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'andersoncollab');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2106', 'f4615118', 'white-label-systems', 'White Label Systems', '1.0.0', 'design', 'T14 — NAHRA', 'T14', 'commercial', 'White-label systems enable a single codebase to serve multiple brands simultaneously. This skill covers the complete architecture for CSS custom property theming, tenant configuration management, dynamic brand switching, and multi-tenant SaaS customization without code changes.', '', '', 'Commercial', 7, 'advisory', 10.0, 'draft', 'andersoncollab');
