INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2132', '00136357', 'api-pentest', 'Api Pentest', '1.0.0', 'pentesting', 'T08 — ZURD', 'T08', 'security', 'Targeted API penetration testing using a GTFO-first approach: find the highest-impact vulnerability fast, prove it with a PoC, and move on. Covers five attack families: AuthN/AuthZ, BOLA/IDOR, Input Validation, SSRF, and Business Logic. Each family is a loadable module with specific test cases, payloads, and PoC templates. Trigger when user mentions "API pentest", "API security test", "test this API", "find vulnerabilities in this endpoint", "BOLA", "IDOR", "broken auth", "injection test", "SSRF', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'Poatan222/Skills-security');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2133', '9c37820c', 'cspm-prowler', 'Cspm Prowler', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Analyze Prowler CSPM scan outputs, prioritize cloud misconfigurations by risk, and generate remediation plans with compliance mapping. Supports AWS, Azure, and GCP findings. Trigger when user uploads Prowler output files (.csv, .json, .html), mentions "Prowler", "CSPM", "cloud security posture", "cloud misconfiguration", "CIS benchmark", "cloud compliance scan", or asks about cloud security findings. Also trigger when user pastes Prowler CLI output or asks how to run Prowler against their cloud ', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'Poatan222/Skills-security');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2134', '20d987db', 'secure-code-review', 'Secure Code Review', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Perform security-focused code review using taint analysis, data flow analysis, control flow analysis, and framework-specific insecure patterns. Covers Java/Spring Boot, Python/Django/Flask, and Node.js/Express. Identifies vulnerabilities at the code level with exact file/line references, PoC scenarios, and remediation code. Trigger when user mentions "code review", "security review", "secure code review", "find vulnerabilities in this code", "audit this code", "is this code secure", "taint analy', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'Poatan222/Skills-security');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-2135', '48ab033c', 'threat-modeling', 'Threat Modeling', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Generate STRIDE-based threat models from architecture descriptions, diagrams, or design documents. Produces a structured threat register with risk ratings, mitigations, and data flow analysis. Trigger when user mentions "threat model", "STRIDE", "attack surface", "security review", "design review", "architecture review", "threat assessment", or uploads architecture diagrams, system design docs, or data flow diagrams. Also trigger when user describes a new feature or system and asks about securit', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'Poatan222/Skills-security');
